var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"아.","JPN":"あ。","ENG":"Oh.","TWN":"啊。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_06"},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"이런! 괜찮으십니까?","JPN":"おや！　大丈夫ですか？","ENG":"My goodness! Are you okay?","TWN":"哎呀！您沒事吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"손에 화상을 입으신 것 같은데 의사를 부르겠습니다.","JPN":"手に火傷をされたようですね。医師を呼んできます。","ENG":"You seem to have burned your hand. Let me call a doctor for you.","TWN":"您的手好像被燒傷了，我叫醫生來。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"아뇨, 괜찮아요. 근처의 난로에라도 스친 모양이죠.","JPN":"いいえ、大丈夫です。近くのストーブにでもかすめたのでしょう。","ENG":"That's alright. I must have touched the heater or something.","TWN":"不，不用了，可能是不小心碰到附近的暖爐了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만......","JPN":"でも……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"별로 큰 상처도 아닌 걸요.","JPN":"大した怪我ではありません。","ENG":"It's only a small burn.","TWN":"傷口也不大。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"저희 공연을 보셨다면 아시겠지만 전 고통을 꽤나 즐기는 편이랍니다.","JPN":"劇団の公演を見たならおわかりだと思いますが、私は割と苦痛を楽しむほうなんです。","ENG":"If you've seen my performance, you'll realize I rather enjoy pain.","TWN":"如果你看了我們的演出，那應該明白，我是一個享受痛苦的人。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"이런 예상치 못한 아픔도 여흥으로는 나쁘지 않네요.","JPN":"こんな予想外の痛みも余興としては悪くないですね。","ENG":"A little unexpected pain like this is pleasant enough.","TWN":"這種意想不到的痛苦，可以當作是助興。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"그, 그렇군요. 알겠습니다.","JPN":"そ、そうですか。わかりました。","ENG":"I-I see. Understood.","TWN":"是、是嗎，明白了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"그보다 무대 준비는 어떻게 되어 가죠?","JPN":"それより、舞台の準備はどうですか？","ENG":"How is the stage coming along?","TWN":"舞臺準備的如何了？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"아, 네. 할로윈 코스튬 경연까지는 마무리 될 것 같습니다.","JPN":"ああ、はい。ハロウィンコスチュームコンテストまでには終わりそうです。","ENG":"I think we should be ready by the Halloween costume contest.","TWN":"啊，萬聖節扮裝大賽前應該能準備好。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"고마워요. 정말 재미있는 할로윈이 될 것 같군요.","JPN":"ありがとう。本当に楽しいハロウィンになりそうですね。","ENG":"Thank you. This will be a wonderful Halloween.","TWN":"謝謝，今年的萬聖節應該很有趣。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"네. 그럼 전 이만 가보겠습니다.","JPN":"はい。では、私は先に失礼します。","ENG":"I hope so. Well, then. I'd better get going.","TWN":"嗯，那我先告辭了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"그래, 분명해. 느낄 수 있어.","JPN":"ああ、間違いない。感じるわ。","ENG":"Yes, I'm sure of it. I can feel its presence.","TWN":"是的，沒錯，能感覺到。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"이런 곳에 있었구나. 나의 최고의 인형.","JPN":"こんな所にいたのね。私の最高の人形。","ENG":"So that's where you were, my greatest puppet.","TWN":"原來在這裡啊，我最優秀的木偶。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"하지만 누구일까? 인형의 실을 불태우고 내게까지 이런 고통을 준 사람은?","JPN":"しかし、誰かしら？　人形の糸を燃やして、私にまでこれほどの苦痛を与えた人は？","ENG":"But who could have burned your strings and given me such pain?","TWN":"但到底是誰焚燒了木偶的繩子，還給我造成痛苦的呢？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"아직 서툴지만...... 가슴을 두근거리게 하는 이 화염의 통증.","JPN":"まだ未熟なようだけど……胸をざわつかせるこの炎の痛み。","ENG":"Still clumsy... but this fiery pain makes my heart race.","TWN":"雖然還很生澀……但這火焰帶來的痛苦讓我異常心動。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"아아...... 너무나 기대되는걸?","JPN":"ああ……とても楽しみ。","ENG":"Oh... I do look forward to this immensely...","TWN":"啊……我好期待啊。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"네가 나에게 줄 고통이......","JPN":"あなたが私に与える苦痛が……","ENG":"The suffering you'll grant me...","TWN":"期待你帶給我的痛苦……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"그리고 내가 너에게 선사해 줄 고통과, 비명과......","JPN":"そして私があなたに与える苦痛と、悲鳴……","ENG":"As well as the agony, the screaming...","TWN":"還有我賜予你的痛苦、哀嚎……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARAB_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HARAB_QLIPHOTH_NULL_NULL","text":{"KOREA":"......절망의 몸부림이.","JPN":"……絶望の悪あがきが。","ENG":"and the writhing of despair I will give you.","TWN":"……和充滿絕望的掙扎。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};